// src/pages/SemesterSelection.js
import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';

const SemesterSelection = () => {
  const { courseId, yearId } = useParams();
  const navigate = useNavigate();
  
  const semesters = [1, 2, 3, 4, 5, 6, 7, 8];
  
  const handleSemesterClick = (sem) => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${sem}`);
  };
  
  const handleBack = () => {
    navigate(`/course/${courseId}`);
  };
  
  return (
    <div style={styles.container}>
      <button onClick={handleBack} style={styles.backButton}>
        ← Back to Years
      </button>
      
      <div style={styles.header}>
        <h1>Year {yearId} - Select Semester</h1>
        <p>Choose your semester</p>
      </div>
      
      <div style={styles.semestersGrid}>
        {semesters.map(sem => (
          <div 
            key={sem}
            style={styles.semesterCard}
            onClick={() => handleSemesterClick(sem)}
          >
            <div style={styles.semesterNumber}>{sem}</div>
            <h3>Semester {sem}</h3>
            <p>6-7 Subjects • 24-28 Credits</p>
            <button style={styles.selectButton}>
              View Subjects →
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem 1rem',
    minHeight: '100vh'
  },
  backButton: {
    padding: '0.75rem 1.5rem',
    background: '#4f46e5',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    marginBottom: '2rem'
  },
  header: {
    textAlign: 'center',
    marginBottom: '3rem',
    padding: '2rem',
    background: 'white',
    borderRadius: '15px',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)'
  },
  semestersGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))',
    gap: '1.5rem'
  },
  semesterCard: {
    background: 'white',
    padding: '1.5rem',
    borderRadius: '12px',
    textAlign: 'center',
    cursor: 'pointer',
    transition: 'all 0.3s',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)',
    '&:hover': {
      transform: 'translateY(-5px)',
      boxShadow: '0 10px 25px rgba(0,0,0,0.1)'
    }
  },
  semesterNumber: {
    width: '60px',
    height: '60px',
    background: 'linear-gradient(135deg, #10b981, #34d399)',
    borderRadius: '50%',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    margin: '0 auto 1rem',
    color: 'white',
    fontSize: '1.5rem',
    fontWeight: 'bold'
  },
  selectButton: {
    marginTop: '1rem',
    padding: '0.75rem 1.5rem',
    background: 'linear-gradient(90deg, #10b981, #34d399)',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    width: '100%'
  }
};

export default SemesterSelection;
